    37→void XPBlePollingService::setPlatformCallback(IPlatformCallback* callback) {
    38→    this->callback_ = callback;
    39→    this->logHelper = new LogHelper(callback, PL_SER_TAG);
    40→    INFO_LOG_WITH_LOCATION(this->logHelper, "pollingService init setPlatformCallback");
    41→}
