   102→void XPBlePollingService::bleHardwareUpdate(string &bleHardware) {
   103→    if (bleHardware.empty()) {
   104→        ERROR_LOG_WITH_LOCATION(this->logHelper, "bleHardware is empty");
   105→        return;
   106→    }
   107→    INFO_LOG_WITH_LOCATION(this->logHelper, "bleHardwareUpdate: " + bleHardware);
   108→    if (this->bleHardware != bleHardware || this->finalHardware.empty()) {
   109→        this->bleHardware = bleHardware;
   110→        string covertHardware = convertBleHardware(this->bleHardware);
   111→        if (this->finalHardware != covertHardware) {
   112→            INFO_LOG_WITH_LOCATION(this->logHelper, "finalHardware is not equal to covertHardware");
   113→            this->finalHardware = covertHardware;
   114→            INFO_LOG_WITH_LOCATION(this->logHelper, "finalHardware update to: " + this->finalHardware);
   115→            this->stopBlePollingService();
   116→            this->stopBleLocationService();
   117→            this->startBleLocationService();
   118→            this->startBlePollingService();
   119→        }
   120→    }
   121→}
