   126→        return;
   127→    }
   128→    XPBlePollingConfigParser::parseBleHardwareMap(vehicleTypeCode, bleHardwareMapStr, this->bleHardwareMap);
   129→    string covertHardware = convertBleHardware(this->bleHardware);
   130→    if (this->finalHardware != covertHardware) {
   131→        INFO_LOG_WITH_LOCATION(this->logHelper, "finalHardware is not equal to covertHardware");
   132→        this->finalHardware = covertHardware;
   133→        INFO_LOG_WITH_LOCATION(this->logHelper, "finalHardware update to: " + this->finalHardware);
   134→        this->stopBlePollingService();
   135→        this->stopBleLocationService();
   136→        this->startBleLocationService();
   137→        this->startBlePollingService();
   138→    }
   139→}
