   236→        return;
   237→    }
   238→    bleDisconnectTime = 0;
   239→    bleDisconnectEventHandle = false;
   240→    if (this->bleDisconnectTimer != nullptr) {
   241→        INFO_LOG_WITH_LOCATION(this->logHelper, "bleDisconnectTimer is not null");
   242→        this->bleDisconnectTimer->stop();
   243→        delete this->bleDisconnectTimer;
   244→        this->bleDisconnectTimer = nullptr;
   245→    }
   246→}
