   680→            this->bleLocationManager->updateBleLocationConfig(threshod);
   681→        }
   682→    }
   683→    if ((result == json_parse_result_success || result == json_parse_result_default_value) && this->bleLocationManager != nullptr) {
   684→        return true;
   685→    } else {
   686→        return false;
   687→    }
   688→}
