   690→void XPBlePollingService::_predictWithRssi(const string &jsonStr, const ble_location_version &version, ble_predict_result &output) {
   691→    if (version == ble_location_version_v1) {
   692→        vector<short> rssiV;
   693→        XPRssiModel rssiModel = XPRssiModel(0, "", std::chrono::system_clock::now(), 0);
   694→        json_parse_result result = XPBleRssiParser::parseBleRssiStrV1(jsonStr, rssiModel);
   695→        if ((result == json_parse_result_success || result == json_parse_result_default_value) && this->bleLocationManager != nullptr) {
   696→            if (this->lastRssiArray.size() == 0) {
   697→                string log = "";
   698→                log = log + rssiModel.description();
   699→                INFO_LOG_WITH_LOCATION(this->logHelper,  log);
   700→                this->lastRssiArray.push_back(rssiModel);
   701→            } else {
   702→                XPRssiModel *cacheModel = nullptr;
   703→                for (auto &element : this->lastRssiArray) {
   704→                    if (element.name.compare(rssiModel.name) == 0) {
   705→                        cacheModel = &element;
   706→                        break;
   707→                    }
   708→                }
   709→                if (cacheModel == nullptr) {
   710→                    string log = "";
   711→                    log = log + rssiModel.description();
   712→                    INFO_LOG_WITH_LOCATION(this->logHelper,  log);
   713→                    this->lastRssiArray.push_back(rssiModel);
   714→                } else {
   715→                    auto duration = rssiModel.receiveDate - cacheModel->receiveDate;
   716→                    auto milliseconds = std::chrono::duration_cast<std::chrono::milliseconds>(duration).count();
   717→                    // 判断是否大于2秒（2000毫秒）
   718→                    if (milliseconds > 2000) {
   719→                        string log = "";
   720→                        log = log + "interval more 2s,last:" + cacheModel->description() + ",current:" + rssiModel.description();
   721→                        INFO_LOG_WITH_LOCATION(this->logHelper,  log);
   722→                    }
   723→                    // 判断是否小于300毫秒
   724→                    if (milliseconds < 300) {
   725→                        string log = "";
   726→                        log = log + "interval less 300 ms,last:" + cacheModel->description() + ",current:" + rssiModel.description();
   727→                        INFO_LOG_WITH_LOCATION(this->logHelper,  log);
   728→                    }
   729→                }
   730→                this->lastRssiArray.erase(
   731→                                          std::remove_if(this->lastRssiArray.begin(),
   732→                                                         this->lastRssiArray.end(),
   733→                                                         [&rssiModel](const auto& element) {
   734→                                                             return element.name == rssiModel.name;
   735→                                                         }),
   736→                                          this->lastRssiArray.end()
   737→                                          );
   738→            }
   739→            vector<XPRssiModel> rssiModelArray;
   740→            rssiModelArray.push_back(rssiModel);
   741→            this->bleLocationManager->predictWithRssi(rssiModelArray, output);
   742→        } else {
   743→            output.error = ble_location_error_json_parse_error;
   744→        }
   745→    } else {
   746→        vector<ble_rssi> rssiV;
   747→        vector<XPRssiModel> rssiModelArray;
   748→        json_parse_result result = XPBleRssiParser::parseBleRssiStrV2(jsonStr, rssiModelArray);
   749→        if ((result == json_parse_result_success || result == json_parse_result_default_value) && this->bleLocationManager != nullptr) {
   750→            XPRssiModel *currentModel = nullptr;
   751→            for (auto &element : rssiModelArray) {
   752→                if (element.isCommunicate) {
   753→                    currentModel = &element;
   754→                    break;
   755→                }
   756→            }
   757→            if (this->lastRssiArray.size() == 0) {
   758→                string log = "";
   759→                for (auto &element : rssiModelArray) {
   760→                    log = log + element.description() + ";";
   761→                }
   762→                INFO_LOG_WITH_LOCATION(this->logHelper,  log);
   763→                this->lastRssiArray = rssiModelArray;
   764→            } else {
   765→                XPRssiModel *cacheModel = nullptr;
   766→                for (auto &element : this->lastRssiArray) {
   767→                    if (element.isCommunicate) {
   768→                        cacheModel = &element;
   769→                        break;
   770→                    }
   771→                }
   772→                if (cacheModel != nullptr && currentModel != nullptr) {
   773→                    auto duration = currentModel->receiveDate - cacheModel->receiveDate;
   774→                    auto milliseconds = std::chrono::duration_cast<std::chrono::milliseconds>(duration).count();
   775→                    // 判断是否大于2秒（2000毫秒）
   776→                    if (milliseconds > 300) {
   777→                        string log = "";
   778→                        log = log + "interval more 300ms,last:" + cacheModel->description() + ",current:" + currentModel->description();
   779→                        INFO_LOG_WITH_LOCATION(this->logHelper,  log);
   780→                    }
   781→                    // 判断是否小于300毫秒
   782→                    if (milliseconds < 10) {
   783→                        string log = "";
   784→                        log = log + "interval less 10 ms,last:" + cacheModel->description() + ",current:" + currentModel->description();
   785→                        INFO_LOG_WITH_LOCATION(this->logHelper,  log);
   786→                    }
   787→                }
   788→            }
   789→            this->lastRssiArray = rssiModelArray;
   790→            this->bleLocationManager->predictWithRssi(rssiModelArray, output);
   791→        } else {
   792→            output.error = ble_location_error_json_parse_error;
   793→        }
   794→    }
   795→}
