   805→string XPBlePollingService::convertBleHardware(const string &bleHardware) {
   806→    if (bleHardware.empty()) {
   807→        return bleHardware;
   808→    }
   809→    if (bleHardwareMap.empty()) {
   810→        return bleHardware;
   811→    }
   812→    try {
   813→        vector<string> hardwareArray;
   814→        splitString(bleHardware, '+', hardwareArray);
   815→        string &main = hardwareArray.front();
   816→        string &slave = hardwareArray.back();
   817→        string mainCovert, slaveCovert;
   818→        auto mainIt = bleHardwareMap.find(main);
   819→        if (mainIt != bleHardwareMap.end()) {
   820→            mainCovert = mainIt->second;
   821→        } else {
   822→            mainCovert = main;
   823→        }
   824→        auto slaveIt = bleHardwareMap.find(slave);
   825→        if (slaveIt != bleHardwareMap.end()) {
   826→            slaveCovert = slaveIt->second;
   827→        } else {
   828→            slaveCovert = slave;
   829→        }
   830→        return mainCovert + "+" + slaveCovert;
   831→    } catch (...) {
   832→        return bleHardware;
   833→    }
   834→}
