   836→void XPBlePollingService::startBleDisconnectRevert() {
   837→    bleDisconnectClean();
   838→    auto now = time(nullptr);
   839→    bleDisconnectTime = now;
   840→    this->bleDisconnectTimer = new Timer();
   841→    weak_ptr<XPBlePollingService> weak_this = shared_from_this();
   842→    this->bleDisconnectTimer->start(7 * 1000, [weak_this] {
   843→        try {
   844→            auto strong_this = weak_this.lock();
   845→            if (!strong_this) {
   846→                return; // 对象已销毁，直接返回
   847→            }
   848→            if (strong_this->bleDisconnectEventHandle == true) {
   849→                return;
   850→            }
   851→            strong_this->bleDisconnectEventHandle = true;
   852→            if (strong_this->blePollingManager != nullptr) {
   853→                strong_this->blePollingManager->bleIsDisconnect();
   854→            }
   855→            strong_this->bleDisconnectClean();
   856→            strong_this->stopBlePollingService();
   857→            strong_this->stopBleLocationService();
   858→        } catch (const exception &e) {
