    36→        set(new_value);
    37→        return *this;
    38→    }
    39→
    40→    // 支持隐式转换到T
    41→    operator T() const {
    42→        return get();
    43→    }
    44→
    45→private:
    46→    mutable mutex mtx;
    47→    T value;
    48→};
    49→
